    if ((query_result >= output_buffer && query_result < output_buffer + buffer_size) ||
        (output_buffer >= query_result && output_buffer < query_result + result_len)) {
        /* Buffers overlap - use memmove which handles overlapping regions safely */
        memmove(output_buffer, query_result, result_len);
    } else {
        /* Buffers don't overlap - use memcpy for better performance */
        memcpy(output_buffer, query_result, result_len);
    }

